class FileSystemReceiver {
    public void openFile() {
        System.out.println("Opening file");
    }
    public void writeFile() {
        System.out.println("Writing file");
    }
    public void closeFile() {
        System.out.println("Closing file");
    }
}

class OpenFileCommand implements Command {
    private FileSystemReceiver fileSystem;
    public OpenFileCommand(FileSystemReceiver fileSystem) {
        this.fileSystem = fileSystem;
    }
    public void execute() {
        fileSystem.openFile();
    }
}

class WriteFileCommand implements Command {
    private FileSystemReceiver fileSystem;
    public WriteFileCommand(FileSystemReceiver fileSystem) {
        this.fileSystem = fileSystem;
    }
    public void execute() {
        fileSystem.writeFile();
    }
}

class CloseFileCommand implements Command {
    private FileSystemReceiver fileSystem;
    public CloseFileCommand(FileSystemReceiver fileSystem) {
        this.fileSystem = fileSystem;
    }
    public void execute() {
        fileSystem.closeFile();
    }
}

class FileInvoker {
    private Command command;
    public FileInvoker(Command command) {
        this.command = command;
    }
    public void execute() {
        command.execute();
    }
}

public class CommandPatternDemo {
    public static void main(String[] args) {
        FileSystemReceiver fileSystem = new FileSystemReceiver();
        Command openCommand = new OpenFileCommand(fileSystem);
        Command writeCommand = new WriteFileCommand(fileSystem);
        Command closeCommand = new CloseFileCommand(fileSystem);

        FileInvoker openFile = new FileInvoker(openCommand);
        FileInvoker writeFile = new FileInvoker(writeCommand);
        FileInvoker closeFile = new FileInvoker(closeCommand);

        openFile.execute();
        writeFile.execute();
        closeFile.execute();
    }
}
